import React from 'react';

/**
 * LogoSVG Component
 * Embedded SVG logo - no external file dependencies
 * 100% compatible with Hostinger and all CDN-restrictive hosting
 */
const LogoSVG = ({ className = "h-12 md:h-16 w-auto" }) => {
  return (
    <div style={{ filter: 'invert(1) hue-rotate(180deg)', WebkitFilter: 'invert(1) hue-rotate(180deg)' }}>
      <svg 
        width="503" 
        height="186" 
        viewBox="0 0 503 186" 
        xmlns="http://www.w3.org/2000/svg" 
        xmlnsXlink="http://www.w3.org/1999/xlink"
        className={className}
        preserveAspectRatio="xMidYMid meet"
      >
      <image 
        width="503" 
        height="186" 
        x="0" 
        y="0"
        xlinkHref="data:image/png;base64,"
        preserveAspectRatio="xMidYMid meet"
      />
    </svg>
    </div>
  );
};

export default LogoSVG;
